function escapeHTML(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

export function renderGuideLayer({ id, label, text, open = false }) {
  return renderTextLayer({ id, label, text, open, variant: 'guide' });
}

export function renderTextLayer({ id, label, text, open = true, variant = 'human' }) {
  const state = open ? 'open' : '';
  const hidden = open ? 'false' : 'true';
  const fallback = variant === 'narration'
    ? 'The narration transcript will appear here when this chamber receives a spoken reading.'
    : 'A human-readable translation will appear here when this chamber receives a generated reading.';
  return `<section class="guide-layer text-layer ${variant} ${state}" data-guide-layer="${escapeHTML(id)}">
    <button class="guide-toggle" type="button" data-guide-toggle="${escapeHTML(id)}" aria-expanded="${open ? 'true' : 'false'}">
      <span>${escapeHTML(label)}</span>
      <b>${open ? 'HIDE' : 'REVEAL'}</b>
    </button>
    <div class="guide-body" data-guide-body="${escapeHTML(id)}" aria-hidden="${hidden}">
      ${escapeHTML(text || fallback).replace(/\n/g, '<br><br>')}
    </div>
  </section>`;
}

function escapeSelector(value) {
  return globalThis.CSS?.escape ? CSS.escape(value) : String(value).replace(/"/g, '\\"');
}

export function setGuideOpen(root, id, open = true) {
  const safeId = escapeSelector(id);
  const layer = root?.querySelector?.(`[data-guide-layer="${safeId}"]`);
  const toggle = root?.querySelector?.(`[data-guide-toggle="${safeId}"]`);
  const body = root?.querySelector?.(`[data-guide-body="${safeId}"]`);
  if (!layer || !toggle || !body) return;
  layer.classList.toggle('open', open);
  toggle.setAttribute('aria-expanded', String(open));
  toggle.querySelector('b').textContent = open ? 'HIDE' : 'REVEAL';
  body.setAttribute('aria-hidden', String(!open));
}

export function bindGuideLayer(root) {
  root?.querySelectorAll?.('[data-guide-toggle]').forEach(toggle => {
    toggle.addEventListener('click', () => {
      const id = toggle.dataset.guideToggle;
      const isOpen = root.querySelector(`[data-guide-layer="${escapeSelector(id)}"]`)?.classList.contains('open');
      setGuideOpen(root, id, !isOpen);
    });
  });
}
