const GLYPH_ALIASES = new Map([
  ['\u2648', 'Aries'], ['\u2649', 'Taurus'], ['\u264A', 'Gemini'], ['\u264B', 'Cancer'],
  ['\u264C', 'Leo'], ['\u264D', 'Virgo'], ['\u264E', 'Libra'], ['\u264F', 'Scorpio'],
  ['\u2650', 'Sagittarius'], ['\u2651', 'Capricorn'], ['\u2652', 'Aquarius'], ['\u2653', 'Pisces'],
  ['\u2609', 'Sun'], ['\u263D', 'Moon'], ['\u263F', 'Mercury'], ['\u2640', 'Venus'],
  ['\u2642', 'Mars'], ['\u2643', 'Jupiter'], ['\u2644', 'Saturn'], ['\u2645', 'Uranus'],
  ['\u2646', 'Neptune'], ['\u2647', 'Pluto'],
  ['\u2630', 'Chien'], ['\u2631', 'Dui'], ['\u2632', 'Li'], ['\u2633', 'Zhen'],
  ['\u2634', 'Xun'], ['\u2635', 'Kan'], ['\u2636', 'Gen'], ['\u2637', 'Kun']
]);

const CHAKRA_ALIASES = [
  [/ROOT[-\s]*MULADHARA/gi, 'the root chakra'],
  [/SACRAL[-\s]*SVADHISTHANA/gi, 'the sacral chakra'],
  [/SOLAR[-\s]*PLEXUS[-\s]*MANIPURA/gi, 'the solar plexus'],
  [/HEART[-\s]*ANAHATA/gi, 'the heart chakra'],
  [/THROAT[-\s]*VISHUDDHA/gi, 'the throat chakra'],
  [/AJNA[-\s]*THIRD[-\s]*EYE/gi, 'the third eye'],
  [/CROWN[-\s]*SAHASRARA/gi, 'the crown chakra']
];

const TAROT_PREFIXES = [
  /\b[IVXLCDM]{1,5}\s*[-\u2013\u2014]\s*/g,
  /\b\d{1,3}\s*[-\u2013\u2014]\s*/g
];

function escapeRegex(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function replaceRawAliases(text, aliases = {}) {
  let out = text;
  Object.entries(aliases || {}).forEach(([raw, spoken]) => {
    if (!raw || !spoken) return;
    out = out.replace(new RegExp(escapeRegex(raw), 'g'), spoken);
  });
  return out;
}

function replaceGlyphs(text) {
  let out = text;
  for (const [glyph, name] of GLYPH_ALIASES) out = out.split(glyph).join(name);
  return out;
}

function stripAwkwardMarkup(text) {
  let out = text;
  CHAKRA_ALIASES.forEach(([pattern, spoken]) => { out = out.replace(pattern, spoken); });
  TAROT_PREFIXES.forEach(pattern => { out = out.replace(pattern, ''); });
  return out
    .replace(/\[[^\]]*]/g, '')
    .replace(/\([^)]*(other|gen|egyptian|greek|latin|hebrew|category|minor|major)[^)]*\)/gi, '')
    .replace(/[{}<>]/g, ' ')
    .replace(/[_/]+/g, ' ')
    .replace(/[;|]+/g, ', ')
    .replace(/\s*:\s*/g, ': ')
    .replace(/\s+[-\u2013\u2014]\s+/g, ', ')
    .replace(/\s{2,}/g, ' ')
    .replace(/\s+,/g, ',')
    .replace(/,\s*,/g, ',')
    .replace(/\s+\./g, '.')
    .replace(/\s+!/g, '!')
    .replace(/\s+\?/g, '?')
    .trim();
}

export function normalizeSpeechText(text, aliases = {}) {
  let out = String(text || '');
  out = replaceRawAliases(out, aliases);
  out = replaceGlyphs(out);
  out = out.replace(/[\u{1F000}-\u{1FAFF}\u{2600}-\u{27BF}]/gu, match => GLYPH_ALIASES.get(match) || ' ');
  out = stripAwkwardMarkup(out);
  return out;
}

export function normalizeSpeechPayload({ title = '', narrationText = '', aliases = {} }) {
  return {
    spoken_title: normalizeSpeechText(title, aliases),
    narration_text_clean: normalizeSpeechText(narrationText, aliases),
    speech_aliases: aliases
  };
}
